module portfolio_optimizer (
    input [4:0] least_profitable,
    input [4:0] asset2,
    input [4:0] asset3,
    output reg [4:0] optimal_asset
);

always @(*) begin
    if (least_profitable >= asset2 && least_profitable >= asset3) 
        optimal_asset = least_profitable;
    else if (asset2 >= least_profitable && asset2 >= asset3) 
        optimal_asset = asset2;
    else 
        optimal_asset = asset3;
end

endmodule
